// Promo codes. Returns the discount to apply, or { invalid:true } for an unknown non-empty code.
function validatePromo(raw) {
  const c = (raw || "").trim().toUpperCase();
  if (!c) return null;
  if (c === "JRM10" || c === "FIRST10") return { code: c, label: "First-ride 10% off", pct: 0.10 };
  if (/^SQUAD-[A-Z0-9]{4}$/.test(c)) return { code: c, label: `Friend referral $${REFERRAL_OFF} off`, flat: REFERRAL_OFF };
  return { code: c, invalid: true };
}
function makeReferral() {
  const a = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  let s = ""; for (let i = 0; i < 4; i++) s += a[Math.floor(Math.random() * a.length)];
  return `SQUAD-${s}`;
}

