const DOW = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
const MONTHS = ["January","February","March","April","May","June","July","August","September","October","November","December"];
const TODAY = new Date(2026, 5, 24);
const HOURS = Array.from({ length: 16 }, (_, i) => i + 8); // 8 AM .. 11 PM (cells end at midnight)
const keyOf = (y, m, d) => `${y}-${String(m + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;

function hourLabel(h) { const x = ((h % 24) + 24) % 24; const ap = x < 12 ? "AM" : "PM"; let hr = x % 12; if (hr === 0) hr = 12; return `${hr} ${ap}`; }
function hourFull(h) { const x = ((h % 24) + 24) % 24; const ap = x < 12 ? "AM" : "PM"; let hr = x % 12; if (hr === 0) hr = 12; return `${hr}:00 ${ap}`; }
const money = (n) => `$${n.toLocaleString()}`;

function seedHash(s) { let h = 2166136261; for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = Math.imul(h, 16777619); } return h >>> 0; }
function mulberry32(a) { return function () { a |= 0; a = (a + 0x6D2B79F5) | 0; let t = Math.imul(a ^ (a >>> 15), 1 | a); t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t; return ((t ^ (t >>> 14)) >>> 0) / 4294967296; }; }

// scooters tied up by other customers per hour (booking + turnaround buffer), deterministic
// Other customers' confirmed bookings would come from your backend here.
// For this prototype the fleet starts fully open, so every new date shows all 10 free —
// availability only drops from bookings you actually make (plus their turnaround buffer).
function baseTaken(dateKey) {
  // Example bookings occupy the fleet (plus turnaround buffer) so customers cannot double-book them.
  const arr = new Array(16).fill(0);
  SEED_BOOKINGS.filter((b) => b.dateKey === dateKey).forEach((b) => {
    const bufEnd = Math.min(b.end + BUFFER_HOURS, 24);
    for (let h = b.start; h < bufEnd; h++) { const i = h - 8; if (i >= 0 && i < 16) arr[i] += b.qty; }
  });
  return arr;
}
const band = (rem) => (rem <= 0 ? "full" : rem <= 2 ? "low" : rem <= 5 ? "med" : "high");

function priceFor(qty, hours, protect) {
  const sub = qty * hours * RATE;
  const d = Math.round(sub * discountRate(qty * hours));
  const after = sub - d;
  return after + DELIVERY + (protect ? qty * PROTECT_PER : 0);
}
function makeSeed(y, m, d, start, dur, qty, info, protect = true) {
  const end = start + dur;
  return {
    id: `seed-${m}-${d}-${start}-${qty}`,
    dateKey: keyOf(y, m, d), dateLabel: `${DOW[new Date(y, m, d).getDay()]}, ${MONTHS[m]} ${d}`,
    start, end, hours: dur, qty, total: priceFor(qty, dur, protect), protect,
    window: `${hourFull(start)} – ${hourFull(end)}`,
    name: info.name, email: info.email, phone: info.phone, address: info.address, notes: info.notes || "",
    waiverSignedAt: new Date().toISOString(), promo: info.promo || null, ref: info.ref || "SQUAD-DEMO",
  };
}
