/* ============================== APP ============================== */
export default function App() {
  const [cursor, setCursor] = useState({ y: TODAY.getFullYear(), m: TODAY.getMonth() });
  const [dateKey, setDateKey] = useState(null);
  const [dateLabel, setDateLabel] = useState("");
  const [start, setStart] = useState(null);
  const [dur, setDur] = useState(2);
  const [qty, setQty] = useState(1);
  const [protect, setProtect] = useState(true);
  const [pkg, setPkg] = useState(null);
  const [promoCode, setPromoCode] = useState("");
  const [dark, setDark] = useState(true);
  const [bookings, setBookings] = useState([]);  // the customer own session bookings
  const allBookings = useMemo(() => [...SEED_BOOKINGS, ...bookings], [bookings]);  // examples + session, for operator view
  const [drawer, setDrawer] = useState(false);
  const [checkout, setCheckout] = useState(false);
  const [confirmation, setConfirmation] = useState(null);
  const [opOpen, setOpOpen] = useState(false);
  const [toast, setToast] = useState(null);
  const shareApp = async () => {
    const url = window.location.origin;
    const shareData = { title: "JRM Scooters", text: "Family fun on wheels - rent party scooters in Tucson by the hour. Open this link, then tap Share -> Add to Home Screen to install it like an app!", url };
    try {
      if (navigator.share) { await navigator.share(shareData); }
      else { await navigator.clipboard.writeText(url); setToast("Link copied - paste it to a friend!"); setTimeout(() => setToast(null), 3000); }
    } catch (e) { /* share sheet dismissed */ }
  };
  const bookRef = useRef(null);

  const base = useMemo(() => (dateKey ? baseTaken(dateKey) : new Array(16).fill(0)), [dateKey]);
  const mine = useMemo(() => {
    const arr = new Array(16).fill(0);
    if (!dateKey) return arr;
    bookings.filter((b) => b.dateKey === dateKey).forEach((b) => {
      const bufEnd = Math.min(b.end + BUFFER_HOURS, 24);
      for (let h = b.start; h < bufEnd; h++) arr[h - 8] += b.qty;
    });
    return arr;
  }, [dateKey, bookings]);

  const remainingAt = (h) => CAPACITY - Math.min(CAPACITY, base[h - 8] + mine[h - 8]);
  const availFor = (s, e) => { if (s == null || e == null || e <= s) return CAPACITY; let m = CAPACITY; for (let h = s; h < e; h++) m = Math.min(m, remainingAt(h)); return m; };
  const maxDurFrom = (s) => { if (s == null) return 8; let d = 0; for (let h = s; h < 24; h++) { if (remainingAt(h) > 0) d++; else break; } return Math.max(1, Math.min(d, 8)); };
  const end = start != null ? start + Math.min(dur, maxDurFrom(start)) : null;
  const windowAvail = start != null && end != null ? availFor(start, end) : CAPACITY;
  const qtyMax = Math.min(ORDER_MAX, windowAvail);

  /* ---- calendar ---- */
  const first = new Date(cursor.y, cursor.m, 1).getDay();
  const days = new Date(cursor.y, cursor.m + 1, 0).getDate();
  const cells = []; for (let i = 0; i < first; i++) cells.push(null); for (let d = 1; d <= days; d++) cells.push(d);
  const todayKey = keyOf(TODAY.getFullYear(), TODAY.getMonth(), TODAY.getDate());
  const minSerial = TODAY.getFullYear() * 372 + TODAY.getMonth() * 31 + TODAY.getDate();

  function navMonth(dir) {
    let m = cursor.m + dir, y = cursor.y;
    if (m < 0) { m = 11; y--; } if (m > 11) { m = 0; y++; }
    if (y * 12 + m < TODAY.getFullYear() * 12 + TODAY.getMonth()) return;
    setCursor({ y, m });
  }
  function pickDay(d) {
    setDateKey(keyOf(cursor.y, cursor.m, d));
    setDateLabel(`${DOW[new Date(cursor.y, cursor.m, d).getDay()]}, ${MONTHS[cursor.m]} ${d}`);
    setStart(null);
  }
  function clickHour(h) {
    if (remainingAt(h) <= 0) return;
    const d = Math.min(dur, maxDurFrom(h));
    setStart(h); setDur(d);
    setQty((q) => Math.min(Math.max(q, 1), availFor(h, h + d), ORDER_MAX));
  }
  function changeDur(nd) {
    const cap = maxDurFrom(start);
    const d = Math.max(1, Math.min(nd, cap));
    setDur(d);
    if (start != null) setQty((q) => Math.min(Math.max(q, 1), availFor(start, start + d), ORDER_MAX));
  }
  function choosePackage(p) {
    setPkg({ qty: p.qty, hours: p.hours });
    setQty(p.qty); setDur(p.hours); setStart(null);
    if (bookRef.current) bookRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
    setToast(dateKey ? `${p.name} loaded — tap your start time` : `${p.name} loaded — now pick a date and start time`);
    setTimeout(() => setToast(null), 3000);
  }
  function customMode() {
    setPkg(null); setStart(null); setDur(2); setQty(1);
    if (bookRef.current) bookRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  /* ---- pricing ---- */
  const hours = end != null ? end - start : 0;
  const sh = qty * hours;
  const subtotal = sh * RATE;
  const disc = discountRate(sh);
  const discountAmt = Math.round(subtotal * disc);
  const afterDisc = subtotal - discountAmt;
  const promo = validatePromo(promoCode);
  const promoOk = promo && !promo.invalid;
  const promoAmt = promoOk ? (promo.pct ? Math.round(afterDisc * promo.pct) : Math.min(promo.flat, afterDisc)) : 0;
  const afterPromo = afterDisc - promoAmt;
  const delivery = DELIVERY;
  const protection = protect ? qty * PROTECT_PER : 0;
  const total = afterPromo + delivery + protection;
  const canBook = dateKey && hours > 0 && qty >= 1 && qty <= qtyMax;

  function finishBooking(details) {
    const ref = makeReferral();
    const b = {
      id: dateKey + start + end + qty + Date.now(),
      dateKey, dateLabel, start, end, hours, qty, total, protect,
      window: `${hourFull(start)} – ${hourFull(end)}`,
      name: details.name, email: details.email, phone: details.phone, address: details.address, notes: details.notes,
      waiverSignedAt: details.signedAt, promo: promoOk ? promo.code : null, ref,
    };
    setBookings((p) => [...p, b]);
    setConfirmation(b);
    setCheckout(false);
    setStart(null); setPkg(null); setQty(1); setDur(2); setPromoCode("");
  }

  const availLabel = hours === 0 ? "Pick a window" : windowAvail <= 0 ? "Booked" : windowAvail <= 3 ? `Only ${windowAvail} left` : "Available";

  return (
    <div style={{ ...THEMES[dark ? "dark" : "light"], background: C.paper, minHeight: "100vh", color: C.ink, transition: "background .25s, color .25s" }}>
      {/* solid bar behind the phone status bar (time/battery) so nothing overlaps or blurs */}
      <div style={{ position: "fixed", top: 0, left: 0, right: 0, height: "env(safe-area-inset-top)", background: C.paper, zIndex: 60 }} />
      <style>{FONTS}</style>

      {/* NAV */}
      <header style={{ position: "sticky", top: 0, zIndex: 40, background: "var(--header)", backdropFilter: "blur(12px)", borderBottom: `1px solid ${C.line}`, paddingTop: "env(safe-area-inset-top)" }}>
        <div style={{ maxWidth: 1120, margin: "0 auto", padding: "13px 20px", display: "flex", alignItems: "center", gap: 14 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 9 }}>
            <div style={{ width: 34, height: 34, borderRadius: 11, background: C.grad, display: "grid", placeItems: "center", boxShadow: "0 6px 18px -6px rgba(166,230,53,.4)" }}><Zap size={19} color="#0B0D08" fill="#0B0D08" /></div>
            <span className="disp" style={{ fontSize: "clamp(18px,5vw,23px)", fontWeight: 800, letterSpacing: "-.02em" }}>JRM <span style={{ color: C.violet }}>Scooters</span></span>
          </div>
          <div className="hide-sm" style={{ marginLeft: 14, alignItems: "center", gap: 6, color: C.mute, fontSize: 13.5, fontWeight: 600 }}>
            <MapPin size={15} /> Tucson, Arizona · delivered to your event
          </div>
          <button className="softbtn" onClick={() => setDark((d) => !d)} title={dark ? "Switch to light mode" : "Switch to dark mode"} style={{ marginLeft: "auto", width: 38, height: 38, borderRadius: 999, background: C.surface, border: `1px solid ${C.line}`, color: C.ink, display: "grid", placeItems: "center" }}>
            {dark ? <Sun size={17} color={C.amber} /> : <Moon size={17} color={C.violet} />}
          </button>
          <button className="softbtn" onClick={() => setDrawer(true)} style={{ display: "flex", alignItems: "center", gap: 8, background: C.surface, border: `1px solid ${C.line}`, color: C.ink, padding: "9px 16px", borderRadius: 999, fontWeight: 600, fontSize: 14 }}>
            <CalendarDays size={16} /> Bookings
            {bookings.length > 0 && <span style={{ background: C.pink, borderRadius: 999, minWidth: 20, height: 20, display: "grid", placeItems: "center", fontSize: 12, fontWeight: 700, padding: "0 5px" }}>{bookings.length}</span>}
          </button>
        </div>
      </header>

      {/* HERO */}
      <section style={{ maxWidth: 1120, margin: "0 auto", padding: "40px 20px 6px" }}>
        <div style={{ display: "flex", gap: 28, alignItems: "center", flexWrap: "wrap" }}>
          <div style={{ flex: "1 1 380px", minWidth: 0 }}>
            <div style={{ display: "inline-flex", alignItems: "center", gap: 7, background: C.surface, border: `1px solid ${C.line}`, padding: "6px 13px", borderRadius: 999, fontSize: 13, fontWeight: 600, color: C.violet, marginBottom: 16 }}>
              <span style={{ width: 7, height: 7, borderRadius: 9, background: C.good }} /> delivered to your door · helmets included
            </div>
            <h1 className="disp" style={{ fontSize: "clamp(34px,5.5vw,56px)", lineHeight: .98, fontWeight: 800, letterSpacing: "-.03em" }}>
              Family fun on wheels.{" "}
              <span style={{ background: C.grad, WebkitBackgroundClip: "text", backgroundClip: "text", color: "transparent" }}>By the hour.</span>
            </h1>
            <p style={{ fontSize: 16.5, color: C.mute, marginTop: 14, maxWidth: 480, lineHeight: 1.5 }}>
              Rent party scooters across Tucson for birthdays, school events, and corporate outings. Pick your hours, choose how many you need, and we deliver them to your door.
            </p>
          </div>
          <div style={{ flex: "1 1 240px", maxWidth: 340, minWidth: 0, margin: "0 auto" }}>
            <img src={FAMILY_IMG} alt="A family riding JRM scooters together in Tucson" style={{ width: "100%", borderRadius: 16, border: `1px solid ${C.line}`, display: "block", boxShadow: "0 20px 50px -28px rgba(166,230,53,.4)" }} />
          </div>
        </div>

        <button className="softbtn" onClick={shareApp} style={{ marginTop: 22, display: "flex", alignItems: "center", justifyContent: "center", gap: 9, width: "100%", maxWidth: 440, padding: "13px 18px", borderRadius: 14, background: C.grad, color: "#0B0D08", fontWeight: 800, fontSize: 15, boxShadow: "0 14px 34px -16px rgba(166,230,53,.5)" }}>
          <Share2 size={18} color="#0B0D08" /> Love it? Share JRM with friends
        </button>

        <div style={{ display: "flex", gap: 2, marginTop: 22, overflowX: "auto", paddingBottom: 6 }}>
          {LINEUP.map((f, i) => (
            <div key={i} style={{ flex: "0 0 104px", animation: "floaty 5s ease-in-out infinite", animationDelay: `${i * 0.18}s` }} title={`${f.name} · ${f.type}`}>
              <ScooterArt color={f.color} />
            </div>
          ))}
        </div>

        <div className="steps" style={{ marginTop: 18 }}>
          {[
            { i: CalendarDays, t: "Pick your hours", d: "Choose a day and tap the time window you need." },
            { i: Truck, t: "We deliver", d: "Scooters arrive charged, with helmets included." },
            { i: PartyPopper, t: "Ride, then we return", d: "Cruise your event — we pick everything up after." },
          ].map((s, i) => (
            <div key={i} style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 16, padding: 16, display: "flex", gap: 12, alignItems: "flex-start" }}>
              <div style={{ width: 38, height: 38, borderRadius: 11, background: `rgba(166,230,53,.08)`, display: "grid", placeItems: "center", flexShrink: 0 }}><s.i size={19} color={C.violet} /></div>
              <div><div className="disp" style={{ fontWeight: 700, fontSize: 15.5 }}>{s.t}</div><div style={{ fontSize: 13.5, color: C.mute, marginTop: 2, lineHeight: 1.4 }}>{s.d}</div></div>
            </div>
          ))}
        </div>
        <p style={{ fontSize: 13, color: C.mute, marginTop: 12, display: "flex", alignItems: "center", gap: 7 }}>
          <Clock size={14} /> We keep a 2-hour turnaround between rentals, so every scooter shows up clean and fully charged.
        </p>
      </section>

      {/* PACKAGES */}
      <section style={{ maxWidth: 1120, margin: "0 auto", padding: "34px 20px 8px" }}>
        <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between", marginBottom: 14, gap: 12, flexWrap: "wrap" }}>
          <div>
            <h2 className="disp" style={{ fontSize: "clamp(21px,5.5vw,26px)", fontWeight: 800, letterSpacing: "-.02em" }}>Start with a package</h2>
            <p style={{ color: C.mute, fontSize: 14.5, marginTop: 2 }}>Tap one to pre-fill, then pick your date. Bigger groups save more.</p>
          </div>
          <button className="softbtn" onClick={customMode} style={{ display: "flex", alignItems: "center", gap: 7, background: C.surface, border: `1px solid ${C.line}`, color: C.ink, padding: "10px 16px", borderRadius: 12, fontWeight: 600, fontSize: 14 }}>
            <Plus size={16} /> Build your own
          </button>
        </div>

        <div className="pkg-grid">
          {PACKAGES.map((p) => {
            const psh = p.qty * p.hours, pd = discountRate(psh), base$ = psh * RATE, price = Math.round(base$ * (1 - pd)), Icon = p.icon;
            return (
              <button key={p.id} className="pkg softbtn" onClick={() => choosePackage(p)}
                style={{ textAlign: "left", background: C.surface, border: `1.5px solid ${p.popular ? C.pink : C.line}`, color: C.ink, position: "relative" }}>
                {p.popular && <span style={{ position: "absolute", top: -11, right: 16, background: C.grad, color: "#0B0D08", fontSize: 11.5, fontWeight: 700, padding: "4px 10px", borderRadius: 999 }}>Most booked</span>}
                <div className="pkg-ico" style={{ background: `rgba(166,230,53,.08)` }}><Icon size={20} color={C.violet} /></div>
                <div className="disp pkg-name" style={{ fontWeight: 700 }}>{p.name}</div>
                <div style={{ fontSize: 13.5, color: C.mute, marginTop: 2 }}>{p.tag}</div>
                <div style={{ display: "flex", gap: 6, marginTop: 12, flexWrap: "wrap" }}>
                  <span style={chip}>{p.qty} scooters</span>
                  <span style={chip}>{p.hours} {p.hours > 1 ? "hours" : "hour"}</span>
                  {pd > 0 && <span style={{ ...chip, background: `rgba(166,230,53,.1)`, color: C.good }}>{Math.round(pd * 100)}% off</span>}
                </div>
                <div style={{ display: "flex", alignItems: "baseline", gap: 8, marginTop: 14 }}>
                  <span className="disp pkg-price" style={{ fontWeight: 800, color: C.violet }}>{money(price)}</span>
                  {pd > 0 && <span style={{ color: C.mute, textDecoration: "line-through", fontSize: 15 }}>{money(base$)}</span>}
                </div>
                <div className="pkg-fine" style={{ fontSize: 12.5, color: C.mute, marginTop: 1 }}>plus delivery and optional protection</div>
              </button>
            );
          })}
        </div>
      </section>

      {/* BOOKING */}
      <section ref={bookRef} style={{ maxWidth: 1120, margin: "0 auto", padding: "30px 20px 10px", scrollMarginTop: 76 }}>
        <h2 className="disp" style={{ fontSize: "clamp(21px,5.5vw,26px)", fontWeight: 800, letterSpacing: "-.02em", marginBottom: 14 }}>{pkg ? "Lock in your event" : "Build your booking"}</h2>
        <div style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 24, overflow: "hidden", boxShadow: "0 18px 50px -30px rgba(0,0,0,.35)" }}>
          <div className="book-grid">
            {/* LEFT: calendar + hours */}
            <div style={{ padding: 24, borderRight: `1px solid ${C.line}` }}>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
                <span className="disp" style={{ fontSize: 18, fontWeight: 700 }}>{MONTHS[cursor.m]} {cursor.y}</span>
                <div style={{ display: "flex", gap: 6 }}>
                  <button className="softbtn" onClick={() => navMonth(-1)} style={navBtn}><ChevronLeft size={18} /></button>
                  <button className="softbtn" onClick={() => navMonth(1)} style={navBtn}><ChevronRight size={18} /></button>
                </div>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 3, marginBottom: 4 }}>
                {["S","M","T","W","T","F","S"].map((d, i) => <div key={i} style={{ textAlign: "center", fontSize: 11.5, fontWeight: 700, color: C.mute }}>{d}</div>)}
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 3 }}>
                {cells.map((d, i) => {
                  if (!d) return <div key={i} />;
                  const k = keyOf(cursor.y, cursor.m, d), serial = cursor.y * 372 + cursor.m * 31 + d;
                  const past = serial < minSerial, sel = k === dateKey, isToday = k === todayKey;
                  return (
                    <button key={i} className="daybtn" disabled={past} onClick={() => pickDay(d)}
                      style={{ aspectRatio: "1", borderRadius: 11, fontSize: 14, fontWeight: 600, background: sel ? C.grad : "transparent", color: sel ? "#0B0D08" : past ? "#5C6448" : C.ink, cursor: past ? "not-allowed" : "pointer", border: isToday && !sel ? `1.5px solid ${C.violet}` : "1.5px solid transparent" }}>
                      {d}
                    </button>
                  );
                })}
              </div>

              <div style={{ height: 1, background: C.line, margin: "18px 0 14px" }} />

              {!dateKey ? (
                <div style={{ display: "grid", placeItems: "center", textAlign: "center", color: C.mute, fontSize: 14, padding: "26px 0" }}>
                  <div><CalendarDays size={26} color={C.line} style={{ marginBottom: 8 }} /><br />Pick a day to see open times</div>
                </div>
              ) : (
                <>
                  <div style={{ fontSize: 13.5, fontWeight: 700, marginBottom: 10 }}>Tap your start time</div>
                  <div className="hour-grid">
                    {HOURS.map((h) => {
                      const rem = remainingAt(h), full = rem <= 0;
                      const inSel = start != null && end != null && h >= start && h < end;
                      const bc = bandColor[band(rem)];
                      const party = h >= 18 && h <= 22;
                      const fillPct = Math.max(10, Math.round((rem / CAPACITY) * 100));
                      return (
                        <button key={h} className="hr-cell" disabled={full} onClick={() => clickHour(h)}
                          title={full ? `${hourFull(h)} – ${hourFull(h + 1)} · booked` : `${hourFull(h)} – ${hourFull(h + 1)} · ${rem} available`}
                          style={{ height: 56, borderRadius: 10, padding: "7px 5px 6px", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "space-between", cursor: full ? "not-allowed" : "pointer", background: inSel ? C.grad : full ? "var(--cellfull)" : C.surface, backgroundSize: inSel ? "200% 100%" : undefined, animation: inSel ? "shimmer 2.5s linear infinite alternate" : undefined, border: inSel ? "1px solid transparent" : party ? `1px solid rgba(255,194,75,.4)` : `1px solid ${C.line}`, opacity: full ? .7 : 1 }}>
                          <span className="disp" style={{ fontSize: 12.5, fontWeight: 700, color: inSel ? "#0B0D08" : full ? C.mute : C.ink, lineHeight: 1 }}>{hourLabel(h)}</span>
                          {full ? (
                            <span style={{ fontSize: 8.5, fontWeight: 700, color: C.mute }}>Booked</span>
                          ) : rem <= 2 ? (
                            <span style={{ fontSize: 8.5, fontWeight: 700, color: inSel ? "#0B0D08" : C.low }}>{rem} left</span>
                          ) : (
                            <div style={{ width: "84%", height: 5, borderRadius: 4, background: inSel ? "rgba(255,255,255,.4)" : "var(--track)", overflow: "hidden" }}>
                              <div style={{ width: `${fillPct}%`, height: "100%", borderRadius: 4, background: inSel ? "#0B0D08" : bc }} />
                            </div>
                          )}
                        </button>
                      );
                    })}
                  </div>
                  <p style={{ fontSize: 12, color: C.mute, marginTop: 10, lineHeight: 1.45 }}>
                    The bar under each time shows how many scooters are still free. A gold outline marks evening party hours (6:00–11:00 PM).
                  </p>

                  <div style={{ marginTop: 18 }}>
                    <div style={{ fontSize: 13.5, fontWeight: 700, marginBottom: 8 }}>How long?</div>
                    <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 9 }}>
                      <button className="softbtn" onClick={() => changeDur(dur - 1)} disabled={dur <= 1} style={stepBtn(dur <= 1)}><Minus size={18} /></button>
                      <div style={{ flex: 1, textAlign: "center" }}>
                        <span className="disp" style={{ fontSize: 28, fontWeight: 800 }}>{dur}</span>
                        <span style={{ color: C.mute, fontWeight: 600 }}> {dur > 1 ? "hours" : "hour"}</span>
                      </div>
                      <button className="softbtn" onClick={() => changeDur(dur + 1)} disabled={start != null && dur >= maxDurFrom(start)} style={stepBtn(start != null && dur >= maxDurFrom(start))}><Plus size={18} /></button>
                    </div>
                    <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                      {[1, 2, 3, 4, 5, 6].map((n) => {
                        const over = start != null && n > maxDurFrom(start);
                        return (
                          <button key={n} className="softbtn" disabled={over} onClick={() => changeDur(n)}
                            style={{ flex: 1, minWidth: 44, padding: "8px 0", borderRadius: 9, fontSize: 13.5, fontWeight: 700, border: `1px solid ${dur === n ? "transparent" : C.line}`, background: dur === n ? C.violet : C.surface, color: dur === n ? "#0B0D08" : over ? "#5C6448" : C.ink, cursor: over ? "not-allowed" : "pointer" }}>{n}</button>
                        );
                      })}
                    </div>
                    {start != null && maxDurFrom(start) < 6 && (
                      <p style={{ fontSize: 12, color: C.mute, marginTop: 8 }}>Up to {maxDurFrom(start)} {maxDurFrom(start) > 1 ? "hours" : "hour"} fit from this start time before the next busy block.</p>
                    )}
                  </div>
                </>
              )}
            </div>

            {/* RIGHT: order builder */}
            <div style={{ padding: 24, display: "flex", flexDirection: "column" }}>
              <div style={{ background: C.paper, borderRadius: 14, padding: 14, marginBottom: 16 }}>
                <Line k="Date" v={dateKey ? dateLabel : "Not picked yet"} />
                <Line k="Time window" v={hours > 0 ? `${hourFull(start)} – ${hourFull(end)}` : "Not picked yet"} />
                <Line k="Length" v={hours > 0 ? `${hours} ${hours > 1 ? "hours" : "hour"}` : "—"} />
                <Line k="Availability" v={availLabel} accent={windowAvail <= 3} />
              </div>

              <label style={{ fontSize: 13.5, fontWeight: 700, marginBottom: 8, display: "block" }}>How many scooters?</label>
              <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 6 }}>
                <button className="softbtn" onClick={() => setQty((q) => Math.max(1, q - 1))} disabled={qty <= 1} style={stepBtn(qty <= 1)}><Minus size={18} /></button>
                <div style={{ flex: 1, textAlign: "center" }}>
                  <span className="disp" style={{ fontSize: 34, fontWeight: 800 }}>{qty}</span>
                  <div style={{ color: C.mute, fontWeight: 600, fontSize: 12.5, marginTop: -2 }}>up to {qtyMax} available</div>
                </div>
                <button className="softbtn" onClick={() => setQty((q) => Math.min(qtyMax, q + 1))} disabled={qty >= qtyMax} style={stepBtn(qty >= qtyMax)}><Plus size={18} /></button>
              </div>
              <div style={{ display: "flex", gap: 6, marginBottom: 16, flexWrap: "wrap" }}>
                {[2, 5, 8, 10].map((n) => (
                  <button key={n} className="softbtn" disabled={n > qtyMax} onClick={() => setQty(n)}
                    style={{ flex: 1, minWidth: 52, padding: "7px 0", borderRadius: 9, fontSize: 13, fontWeight: 700, border: `1px solid ${qty === n ? "transparent" : C.line}`, background: qty === n ? C.violet : C.surface, color: qty === n ? "#0B0D08" : n > qtyMax ? "#5C6448" : C.ink, cursor: n > qtyMax ? "not-allowed" : "pointer" }}>{n}</button>
                ))}
              </div>

              <button className="softbtn" onClick={() => setProtect((p) => !p)}
                style={{ textAlign: "left", display: "flex", gap: 12, alignItems: "flex-start", padding: 13, borderRadius: 14, border: `1.5px solid ${protect ? C.violet : C.line}`, background: protect ? `rgba(166,230,53,.05)` : C.surface, marginBottom: 18 }}>
                <div style={{ width: 22, height: 22, borderRadius: 7, marginTop: 1, background: protect ? C.grad : C.surface, border: protect ? "none" : `1.5px solid ${C.line}`, display: "grid", placeItems: "center", flexShrink: 0 }}>{protect && <Check size={14} color="#0B0D08" />}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", gap: 8 }}>
                    <span style={{ fontWeight: 700, fontSize: 14.5, display: "flex", alignItems: "center", gap: 6 }}><ShieldCheck size={16} color={C.violet} /> Damage protection</span>
                    <span style={{ fontWeight: 700, fontSize: 14 }}>{money(PROTECT_PER)} each</span>
                  </div>
                  <p style={{ fontSize: 12.5, color: C.mute, marginTop: 3, lineHeight: 1.4 }}>Covers accidental dings, scratches, and scuffs. Skip it and you're responsible for repair costs. Does not cover theft or reckless damage.</p>
                </div>
              </button>

              <div style={{ marginTop: "auto" }}>
                <div style={{ marginBottom: 12 }}>
                  <label style={{ fontSize: 13, fontWeight: 700, marginBottom: 6, display: "flex", alignItems: "center", gap: 6 }}><Ticket size={15} color={C.violet} /> Promo or referral code</label>
                  <input value={promoCode} onChange={(e) => setPromoCode(e.target.value)} placeholder="e.g. JRM10 or SQUAD-AB12"
                    style={{ width: "100%", padding: "11px 13px", borderRadius: 11, border: `1.5px solid ${promoOk ? C.good : promo && promo.invalid ? C.low : C.line}`, fontSize: 14, fontWeight: 600, color: C.ink, background: C.surface, textTransform: "uppercase", outline: "none" }} />
                  {promoOk && <p style={{ fontSize: 12, color: C.good, fontWeight: 600, marginTop: 5, display: "flex", alignItems: "center", gap: 5 }}><Check size={13} /> {promo.label} applied</p>}
                  {promo && promo.invalid && <p style={{ fontSize: 12, color: C.low, fontWeight: 600, marginTop: 5 }}>That code isn't valid. Try JRM10 for your first ride.</p>}
                </div>
                {hours > 0 ? (
                  <div style={{ background: C.paper, borderRadius: 14, padding: "13px 15px", marginBottom: 12 }}>
                    <Row label={`${money(RATE)} × ${qty} scooter${qty > 1 ? "s" : ""} × ${hours} ${hours > 1 ? "hours" : "hour"}`} val={money(subtotal)} />
                    {disc > 0 && <Row label={`${tierName(sh)} discount (${Math.round(disc * 100)}%)`} val={`−${money(discountAmt)}`} good />}
                    {promoAmt > 0 && <Row label={promo.label} val={`−${money(promoAmt)}`} good />}
                    <Row label="Delivery and pickup" val={delivery === 0 ? "Free" : money(delivery)} good={delivery === 0} mute={delivery !== 0} />
                    {protect && <Row label={`Damage protection × ${qty}`} val={money(protection)} mute />}
                    <div style={{ height: 1, background: C.line, margin: "9px 0" }} />
                    <Row label="Total" val={money(total)} bold />
                  </div>
                ) : (
                  <div style={{ display: "flex", alignItems: "center", gap: 8, color: C.mute, fontSize: 13.5, marginBottom: 12 }}>
                    <Clock size={15} /> Pick a date and time window to see your price
                  </div>
                )}
                <button className="softbtn" disabled={!canBook} onClick={() => setCheckout(true)}
                  style={{ width: "100%", padding: 15, borderRadius: 14, fontWeight: 700, fontSize: 15.5, color: canBook ? "#0B0D08" : C.mute, background: canBook ? C.grad : "var(--disabled)", cursor: canBook ? "pointer" : "not-allowed", boxShadow: canBook ? "0 14px 30px -12px rgba(166,230,53,.4)" : "none", display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
                  {!dateKey ? "Pick a date" : hours === 0 ? "Pick your hours" : windowAvail === 0 ? "Booked — try another time" : <>Review and sign · {money(total)} <ArrowRight size={17} /></>}
                </button>
                <p style={{ textAlign: "center", fontSize: 12, color: C.mute, marginTop: 9 }}>Free cancellation up to 24 hours before · helmets included</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* LINEUP */}
      <section style={{ maxWidth: 1120, margin: "0 auto", padding: "30px 20px 70px" }}>
        <h2 className="disp" style={{ fontSize: "clamp(21px,5.5vw,26px)", fontWeight: 800, letterSpacing: "-.02em" }}>The lineup</h2>
        <p style={{ color: C.mute, fontSize: 14.5, marginTop: 2, marginBottom: 16 }}>Every booking is a mix — speedy electric scooters, retro cruisers, kid-friendly kicks, and seated rides so everyone can join in.</p>
        <div className="fleet-grid">
          {LINEUP.map((f, i) => (
            <div key={i} className="fleet-card" style={{ background: C.surface, border: `1px solid ${C.line}`, borderRadius: 18, overflow: "hidden" }}>
              <div style={{ height: 92, background: `linear-gradient(160deg, ${f.color}22, ${f.color}08)`, display: "grid", placeItems: "center" }}>
                <div style={{ width: "62%", filter: `drop-shadow(0 6px 8px ${f.color}55)` }}><ScooterArt color={f.color} /></div>
              </div>
              <div style={{ padding: "11px 13px" }}>
                <div className="disp" style={{ fontWeight: 700, fontSize: 15 }}>{f.name}</div>
                <div style={{ fontSize: 12.5, color: f.color, fontWeight: 600, marginTop: 1 }}>{f.type}</div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* FOOTER */}
      <footer style={{ borderTop: `1px solid ${C.line}`, background: C.surface }}>
        <div style={{ maxWidth: 1120, margin: "0 auto", padding: "20px 20px calc(20px + env(safe-area-inset-bottom))", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12, flexWrap: "wrap" }}>
          <span style={{ fontSize: 13, color: C.mute }}>© {BRAND} · Tucson, AZ · (520) 286-3729 · ride. explore. create memories.</span>
          <button className="softbtn" onClick={() => setOpOpen(true)} style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12.5, fontWeight: 600, color: C.mute }}>
            <Lock size={13} /> Operator login
          </button>
        </div>
      </footer>

      {drawer && <Drawer bookings={bookings} onClose={() => setDrawer(false)} onCancel={(id) => setBookings((p) => p.filter((b) => b.id !== id))} />}
      {checkout && (
        <CheckoutModal
          summary={{ dateLabel, window: `${hourFull(start)} – ${hourFull(end)}`, hours, qty, protect, subtotal, discountAmt, disc, sh, promo, promoAmt, delivery, protection, total }}
          onClose={() => setCheckout(false)}
          onConfirm={finishBooking}
        />
      )}
      {confirmation && <ConfirmationModal b={confirmation} onClose={() => setConfirmation(null)} />}
      {opOpen && <OperatorModal bookings={allBookings} onClose={() => setOpOpen(false)} />}

      {toast && (
        <div style={{ position: "fixed", bottom: 24, left: "50%", transform: "translateX(-50%)", zIndex: 80, background: C.surface, color: C.ink, border: `1px solid ${C.line}`, padding: "13px 20px", borderRadius: 14, display: "flex", alignItems: "center", gap: 10, fontWeight: 600, fontSize: 14, boxShadow: "0 18px 40px -12px rgba(0,0,0,.6)", animation: "slidein .35s ease", maxWidth: "92vw" }}>
          <span style={{ width: 22, height: 22, borderRadius: 999, background: C.good, display: "grid", placeItems: "center", flexShrink: 0 }}><Check size={14} color="#0B0D08" /></span>
          {toast}
        </div>
      )}
    </div>
  );
}

/* ============================== SMALL PARTS ============================== */
const chip = { fontSize: 12, fontWeight: 700, padding: "4px 9px", borderRadius: 999, background: C.paper, color: C.ink };
const navBtn = { width: 34, height: 34, borderRadius: 10, background: C.line, display: "grid", placeItems: "center", color: C.ink };
const stepBtn = (off) => ({ width: 46, height: 46, borderRadius: 13, background: off ? C.surface : C.violet, color: off ? C.mute : "#0B0D08", border: off ? `1px solid ${C.line}` : "none", display: "grid", placeItems: "center", cursor: off ? "not-allowed" : "pointer" });

function Line({ k, v, accent }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", padding: "3px 0", fontSize: 13.5, gap: 10 }}>
      <span style={{ color: C.mute, fontWeight: 500, flexShrink: 0 }}>{k}</span>
      <span style={{ fontWeight: 700, color: accent ? C.pink : C.ink, textAlign: "right" }}>{v}</span>
    </div>
  );
}
function Row({ label, val, mute, good, bold }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", padding: "3px 0", fontSize: bold ? 16 : 13.5, fontWeight: bold ? 800 : 600, gap: 10 }}>
      <span style={{ color: good ? C.good : mute ? C.mute : C.ink, fontWeight: bold ? 800 : mute ? 500 : 600 }}>{label}</span>
      <span className={bold ? "disp" : ""} style={{ color: good ? C.good : C.ink, whiteSpace: "nowrap" }}>{val}</span>
    </div>
  );
}

function Drawer({ bookings, onClose, onCancel }) {
  const total = bookings.reduce((a, b) => a + b.total, 0);
  const [confirmId, setConfirmId] = useState(null);
  return (
    <div onClick={onClose} className="scrim" style={{ position: "fixed", inset: 0, zIndex: 70, background: "rgba(0,0,0,.45)" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ position: "absolute", top: 0, right: 0, height: "100%", width: "min(420px,100%)", background: C.surface, boxShadow: "-30px 0 80px -30px rgba(0,0,0,.5)", display: "flex", flexDirection: "column", animation: "slidein .3s ease" }}>
        <div style={{ padding: "calc(20px + env(safe-area-inset-top)) 22px 20px", borderBottom: `1px solid ${C.line}`, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <span className="disp" style={{ fontSize: 21, fontWeight: 800 }}>Your bookings</span>
          <button className="softbtn" onClick={onClose} style={{ width: 34, height: 34, borderRadius: 999, background: C.paper, display: "grid", placeItems: "center" }}><X size={18} /></button>
        </div>
        <div style={{ flex: 1, overflow: "auto", padding: 18 }}>
          {bookings.length === 0 ? (
            <div style={{ textAlign: "center", color: C.mute, marginTop: 70, padding: 20 }}>
              <div style={{ width: 60, height: 60, borderRadius: 18, background: C.paper, display: "grid", placeItems: "center", margin: "0 auto 14px" }}><Plus size={26} color={C.mute} /></div>
              <p style={{ fontWeight: 600, color: C.ink }}>No rides booked yet</p>
              <p style={{ fontSize: 14, marginTop: 4 }}>Pick a package or build your own to get rolling.</p>
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
              {bookings.map((b) => (
                <div key={b.id} style={{ border: `1px solid ${C.line}`, borderRadius: 16, padding: 14 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 8 }}>
                    <div>
                      <div className="disp" style={{ fontWeight: 700, fontSize: 16 }}>{b.qty} scooter{b.qty > 1 ? "s" : ""} · {b.hours} {b.hours > 1 ? "hours" : "hour"}</div>
                      <div style={{ fontSize: 13, color: C.mute, marginTop: 2 }}>{b.dateLabel}</div>
                      <div style={{ fontSize: 13, color: C.mute }}>{b.window}</div>
                    </div>
                    <div className="disp" style={{ fontWeight: 800, fontSize: 16 }}>{money(b.total)}</div>
                  </div>
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginTop: 10 }}>
                    <span style={{ display: "flex", alignItems: "center", gap: 10, fontSize: 12, fontWeight: 600 }}>
                      <span style={{ display: "flex", alignItems: "center", gap: 4, color: b.protect ? C.good : C.mute }}><ShieldCheck size={13} /> {b.protect ? "Protected" : "No cover"}</span>
                      {b.waiverSignedAt && <span style={{ display: "flex", alignItems: "center", gap: 4, color: C.violet }}><PenLine size={13} /> Signed</span>}
                    </span>
                    {confirmId !== b.id && <button className="softbtn" onClick={() => setConfirmId(b.id)} style={{ fontSize: 12.5, color: C.mute, fontWeight: 700 }}>Cancel booking</button>}
                  </div>
                  {confirmId === b.id && (
                    <div style={{ marginTop: 11, background: C.paper, border: `1px solid ${C.line}`, borderRadius: 12, padding: "11px 12px" }}>
                      <div style={{ fontSize: 12.5, color: C.ink, fontWeight: 600, marginBottom: 9, lineHeight: 1.4 }}>Cancel this booking? Cancellations are subject to our policy (free up to 24 hours before the event).</div>
                      <div style={{ display: "flex", gap: 8 }}>
                        <button className="softbtn" onClick={() => setConfirmId(null)} style={{ flex: 1, padding: "9px 0", borderRadius: 10, background: C.surface, border: `1px solid ${C.line}`, color: C.ink, fontWeight: 700, fontSize: 13 }}>Keep booking</button>
                        <button className="softbtn" onClick={() => { onCancel(b.id); setConfirmId(null); }} style={{ flex: 1, padding: "9px 0", borderRadius: 10, background: C.pink, color: "#0B0D08", fontWeight: 800, fontSize: 13 }}>Yes, cancel</button>
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
        {bookings.length > 0 && (
          <div style={{ borderTop: `1px solid ${C.line}`, padding: "18px 22px calc(18px + env(safe-area-inset-bottom))" }}>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 12 }}>
              <span style={{ fontWeight: 600, color: C.mute }}>Total</span>
              <span className="disp" style={{ fontWeight: 800, fontSize: 22 }}>{money(total)}</span>
            </div>
            <button className="softbtn" style={{ width: "100%", padding: 14, borderRadius: 14, background: C.grad, color: "#0B0D08", fontWeight: 700, fontSize: 15.5 }}>Checkout</button>
          </div>
        )}
      </div>
    </div>
  );
}

/* ============================== CHECKOUT + WAIVER ============================== */
function CheckoutModal({ summary, onClose, onConfirm }) {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [address, setAddress] = useState("");
  const [notes, setNotes] = useState("");
  const [sig, setSig] = useState("");
  const [cAge, setCAge] = useState(false);
  const [cRead, setCRead] = useState(false);
  const [cRisk, setCRisk] = useState(false);

  const today = TODAY.toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric", year: "numeric" });
  const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
  const phoneOk = phone.replace(/\D/g, "").length >= 10;
  const addressOk = address.trim().length > 5;
  const detailsOk = name.trim().length > 1 && emailOk && phoneOk && addressOk;
  const waiverOk = cAge && cRead && cRisk && sig.trim().length > 1;
  const ready = detailsOk && waiverOk;

  function submit() {
    if (!ready) return;
    onConfirm({ name: name.trim(), email: email.trim(), phone: phone.trim(), address: address.trim(), notes: notes.trim(), signedAt: new Date().toISOString() });
  }

  return (
    <div onClick={onClose} className="scrim" style={{ position: "fixed", inset: 0, zIndex: 75, background: "rgba(0,0,0,.5)", display: "grid", placeItems: "center", padding: 16 }}>
      <div onClick={(e) => e.stopPropagation()} style={{ width: "min(560px,100%)", maxHeight: "92vh", overflow: "auto", background: C.surface, borderRadius: 24, boxShadow: "0 40px 90px -30px rgba(0,0,0,.7)", animation: "pop .26s cubic-bezier(.2,.8,.2,1)" }}>
        <div style={{ position: "sticky", top: 0, background: C.surface, padding: "18px 22px", borderBottom: `1px solid ${C.line}`, display: "flex", alignItems: "center", justifyContent: "space-between", zIndex: 2 }}>
          <span className="disp" style={{ fontSize: 20, fontWeight: 800 }}>Review and sign</span>
          <button className="softbtn" onClick={onClose} style={{ width: 34, height: 34, borderRadius: 999, background: C.paper, display: "grid", placeItems: "center" }}><X size={18} /></button>
        </div>

        <div style={{ padding: 22 }}>
          {/* order summary */}
          <div style={{ background: C.paper, borderRadius: 14, padding: "13px 15px", marginBottom: 18 }}>
            <Row label={`${summary.qty} scooter${summary.qty > 1 ? "s" : ""} · ${summary.hours} ${summary.hours > 1 ? "hours" : "hour"}`} val={money(summary.subtotal)} />
            <div style={{ fontSize: 12.5, color: C.mute, marginTop: 2, marginBottom: 6 }}>{summary.dateLabel} · {summary.window}</div>
            {summary.disc > 0 && <Row label={`${tierName(summary.sh)} discount`} val={`−${money(summary.discountAmt)}`} good />}
            {summary.promoAmt > 0 && <Row label={summary.promo.label} val={`−${money(summary.promoAmt)}`} good />}
            <Row label="Delivery and pickup" val={summary.delivery === 0 ? "Free" : money(summary.delivery)} good={summary.delivery === 0} mute={summary.delivery !== 0} />
            {summary.protect && <Row label={`Damage protection × ${summary.qty}`} val={money(summary.protection)} mute />}
            <div style={{ height: 1, background: C.line, margin: "9px 0" }} />
            <Row label="Total" val={money(summary.total)} bold />
          </div>

          {/* contact */}
          <div style={{ fontSize: 14, fontWeight: 800, marginBottom: 10 }}>Your details</div>
          <Field icon={Users} placeholder="Full name" value={name} onChange={setName} />
          <Field icon={Mail} placeholder="Email" value={email} onChange={setEmail} ok={email ? emailOk : null} />
          <Field icon={Phone} placeholder="Mobile number" value={phone} onChange={setPhone} ok={phone ? phoneOk : null} />
          <p style={{ fontSize: 12, color: C.mute, marginTop: -2, marginBottom: 18 }}>We'll send your confirmation here and text a reminder the day before.</p>

          {/* drop-off / pickup address */}
          <div style={{ fontSize: 14, fontWeight: 800, marginBottom: 4 }}>Drop-off address</div>
          <p style={{ fontSize: 12.5, color: C.mute, marginBottom: 8 }}>Where we'll deliver — and pick up from afterward.</p>
          <AddressField value={address} onChange={setAddress} />
          <textarea value={notes} onChange={(e) => setNotes(e.target.value)} rows={2} placeholder="Delivery notes (optional) — gate code, where to meet, parking…"
            style={{ width: "100%", padding: "11px 13px", borderRadius: 11, border: `1.5px solid ${C.line}`, fontSize: 13.5, fontWeight: 500, color: C.ink, background: C.surface, outline: "none", resize: "vertical", marginTop: 8, marginBottom: 18, fontFamily: "inherit" }} />

          {/* waiver */}
          <div style={{ fontSize: 14, fontWeight: 800, marginBottom: 4, textTransform: "uppercase", letterSpacing: ".04em" }}>Rental Agreement &amp; Waiver of Liability</div>
          <p style={{ fontSize: 12.5, color: C.mute, marginBottom: 10 }}>Please read carefully — this affects your legal rights.</p>
          <div style={{ maxHeight: 200, overflow: "auto", border: `1px solid ${C.line}`, borderRadius: 12, padding: "12px 14px", background: "#11140C", marginBottom: 14 }}>
            {WAIVER_CLAUSES.map(([h, body], i) => (
              <div key={i} style={{ marginBottom: i === WAIVER_CLAUSES.length - 1 ? 0 : 11 }}>
                <div style={{ fontWeight: 800, fontSize: 12.5, marginBottom: 2 }}>{i + 1}. {h}</div>
                <div style={{ fontSize: 12.5, color: "var(--bodymute)", lineHeight: 1.5 }}>{body}</div>
              </div>
            ))}
          </div>

          <CheckRow on={cAge} set={setCAge} label="I am at least 18 and am the person renting." />
          <CheckRow on={cRead} set={setCRead} label="I have read and understand this agreement, including the risks listed." />
          <CheckRow on={cRisk} set={setCRisk} label="I voluntarily accept those risks and release JRM Scooters for ordinary negligence." />

          <div style={{ marginTop: 12, marginBottom: 4, fontSize: 13, fontWeight: 700, display: "flex", alignItems: "center", gap: 7 }}><PenLine size={15} color={C.violet} /> Type your full name to sign</div>
          <input value={sig} onChange={(e) => setSig(e.target.value)} placeholder="Your signature"
            style={{ width: "100%", padding: "12px 14px", borderRadius: 11, border: `1.5px solid ${sig ? C.violet : C.line}`, fontSize: 17, fontWeight: 700, fontStyle: "italic", color: C.ink, background: C.surface, outline: "none" }} />
          <p style={{ fontSize: 11.5, color: C.mute, marginTop: 6 }}>Signed electronically on {today}. Governed by the laws of the State of Arizona.</p>

          <button className="softbtn" disabled={!ready} onClick={submit}
            style={{ width: "100%", marginTop: 16, padding: 15, borderRadius: 14, fontWeight: 700, fontSize: 15.5, color: ready ? "#0B0D08" : C.mute, background: ready ? C.grad : "var(--disabled)", cursor: ready ? "pointer" : "not-allowed" }}>
            {ready ? `Confirm booking · ${money(summary.total)}` : !detailsOk ? "Add your details to continue" : "Sign the waiver to continue"}
          </button>
        </div>
      </div>
    </div>
  );
}

function Field({ icon: Icon, placeholder, value, onChange, ok }) {
  return (
    <div style={{ position: "relative", marginBottom: 11 }}>
      <Icon size={16} color={C.mute} style={{ position: "absolute", left: 13, top: 14 }} />
      <input value={value} onChange={(e) => onChange(e.target.value)} placeholder={placeholder}
        style={{ width: "100%", padding: "12px 13px 12px 38px", borderRadius: 11, border: `1.5px solid ${ok === false ? C.low : ok === true ? C.good : C.line}`, fontSize: 14, fontWeight: 600, color: C.ink, background: C.surface, outline: "none" }} />
      {ok === true && <Check size={16} color={C.good} style={{ position: "absolute", right: 13, top: 14 }} />}
    </div>
  );
}

function AddressField({ value, onChange }) {
  const [q, setQ] = useState(value || "");
  const [results, setResults] = useState([]);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [failed, setFailed] = useState(false);
  const pickedRef = useRef(value || "");

  useEffect(() => {
    if (q === pickedRef.current) return;
    if (q.trim().length < 4) { setResults([]); setOpen(false); return; }
    setLoading(true);
    const ctrl = new AbortController();
    const t = setTimeout(async () => {
      try {
        const url = `https://nominatim.openstreetmap.org/search?format=jsonv2&addressdetails=1&limit=5&countrycodes=us&q=${encodeURIComponent(q)}`;
        const res = await fetch(url, { signal: ctrl.signal });
        const data = await res.json();
        setResults(Array.isArray(data) ? data : []);
        setOpen(true); setFailed(false);
      } catch (e) {
        if (e.name !== "AbortError") setFailed(true);
      }
      setLoading(false);
    }, 350);
    return () => { clearTimeout(t); ctrl.abort(); };
  }, [q]);

  function pick(r) {
    pickedRef.current = r.display_name;
    setQ(r.display_name); onChange(r.display_name); setOpen(false); setResults([]);
  }

  const okBorder = value && value.trim().length > 5;
  return (
    <div style={{ position: "relative", marginBottom: 6 }}>
      <div style={{ position: "relative" }}>
        <MapPin size={16} color={C.mute} style={{ position: "absolute", left: 13, top: 14 }} />
        <input value={q} onChange={(e) => { setQ(e.target.value); onChange(e.target.value); }} onFocus={() => results.length && setOpen(true)}
          placeholder="Search your venue or home address"
          style={{ width: "100%", padding: "12px 34px 12px 38px", borderRadius: 11, border: `1.5px solid ${okBorder ? C.good : C.line}`, fontSize: 14, fontWeight: 600, color: C.ink, background: C.surface, outline: "none" }} />
        {loading && <span style={{ position: "absolute", right: 13, top: 12, fontSize: 13, color: C.mute }}>…</span>}
        {!loading && okBorder && <Check size={16} color={C.good} style={{ position: "absolute", right: 12, top: 14 }} />}
      </div>
      {open && results.length > 0 && (
        <div style={{ position: "absolute", top: "100%", left: 0, right: 0, marginTop: 4, background: C.surface, border: `1px solid ${C.line}`, borderRadius: 12, boxShadow: "0 16px 36px -14px rgba(0,0,0,.4)", zIndex: 6, overflow: "hidden", maxHeight: 220, overflowY: "auto" }}>
          {results.map((r, i) => (
            <button key={i} className="softbtn" onClick={() => pick(r)}
              style={{ display: "flex", gap: 9, alignItems: "flex-start", width: "100%", textAlign: "left", padding: "10px 13px", borderBottom: i < results.length - 1 ? `1px solid ${C.line}` : "none" }}>
              <MapPin size={14} color={C.violet} style={{ marginTop: 2, flexShrink: 0 }} />
              <span style={{ fontSize: 13, color: C.ink, lineHeight: 1.35 }}>{r.display_name}</span>
            </button>
          ))}
        </div>
      )}
      {failed && <p style={{ fontSize: 11.5, color: C.mute, marginTop: 5 }}>Address lookup is unavailable right now — just type the full address and we'll confirm it with you.</p>}
    </div>
  );
}
function CheckRow({ on, set, label }) {
  return (
    <button className="softbtn" onClick={() => set(!on)} style={{ display: "flex", gap: 10, alignItems: "flex-start", textAlign: "left", width: "100%", marginBottom: 8 }}>
      <div style={{ width: 22, height: 22, borderRadius: 7, marginTop: 1, flexShrink: 0, background: on ? C.grad : C.surface, border: on ? "none" : `1.5px solid ${C.line}`, display: "grid", placeItems: "center" }}>{on && <Check size={14} color="#0B0D08" />}</div>
      <span style={{ fontSize: 13, fontWeight: 500, color: C.ink, lineHeight: 1.4 }}>{label}</span>
    </button>
  );
}

/* ============================== CONFIRMATION ============================== */
function ConfirmationModal({ b, onClose }) {
  const [copied, setCopied] = useState(false);
  function copy() {
    try { navigator.clipboard.writeText(b.ref); } catch (e) {}
    setCopied(true); setTimeout(() => setCopied(false), 1800);
  }
  return (
    <div onClick={onClose} className="scrim" style={{ position: "fixed", inset: 0, zIndex: 78, background: "rgba(0,0,0,.5)", display: "grid", placeItems: "center", padding: 16 }}>
      <div onClick={(e) => e.stopPropagation()} style={{ width: "min(460px,100%)", maxHeight: "92vh", overflow: "auto", background: C.surface, borderRadius: 24, boxShadow: "0 40px 90px -30px rgba(0,0,0,.7)", animation: "pop .26s cubic-bezier(.2,.8,.2,1)", padding: 26, textAlign: "center" }}>
        <div style={{ width: 60, height: 60, borderRadius: 999, background: C.grad, display: "grid", placeItems: "center", margin: "0 auto 14px", boxShadow: "0 14px 30px -10px rgba(166,230,53,.4)" }}><Check size={30} color="#0B0D08" /></div>
        <h2 className="disp" style={{ fontSize: "clamp(21px,5.5vw,26px)", fontWeight: 800, letterSpacing: "-.02em" }}>You're booked!</h2>
        <p style={{ color: C.mute, fontSize: 14.5, marginTop: 6 }}>{b.qty} scooter{b.qty > 1 ? "s" : ""} · {b.dateLabel}<br />{b.window} · {money(b.total)}</p>

        <div style={{ background: C.paper, borderRadius: 14, padding: 14, margin: "18px 0", textAlign: "left" }}>
          <div style={{ display: "flex", gap: 9, alignItems: "flex-start", marginBottom: 9 }}>
            <MapPin size={16} color={C.pink} style={{ marginTop: 1, flexShrink: 0 }} />
            <span style={{ fontSize: 13.5, color: C.ink }}>Delivery &amp; pickup at <b>{b.address}</b></span>
          </div>
          <div style={{ display: "flex", gap: 9, alignItems: "flex-start", marginBottom: 9 }}>
            <Mail size={16} color={C.good} style={{ marginTop: 1, flexShrink: 0 }} />
            <span style={{ fontSize: 13.5, color: C.ink }}>Confirmation sent to <b>{b.email}</b></span>
          </div>
          <div style={{ display: "flex", gap: 9, alignItems: "flex-start" }}>
            <Clock size={16} color={C.violet} style={{ marginTop: 1, flexShrink: 0 }} />
            <span style={{ fontSize: 13.5, color: C.ink }}>We'll text a reminder to <b>{b.phone}</b> the day before, with your delivery window.</span>
          </div>
        </div>

        {/* referral */}
        <div style={{ border: `1.5px dashed ${C.violet}`, borderRadius: 16, padding: 16, background: `rgba(166,230,53,.03)`, textAlign: "left" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 7, fontWeight: 800, fontSize: 14.5, marginBottom: 4 }}><Gift size={17} color={C.violet} /> Share the ride, both save ${REFERRAL_OFF}</div>
          <p style={{ fontSize: 13, color: C.mute, marginBottom: 11 }}>Send friends your code. They get ${REFERRAL_OFF} off their first booking, and you get ${REFERRAL_OFF} off your next one.</p>
          <div style={{ display: "flex", gap: 8 }}>
            <div className="disp" style={{ flex: 1, padding: "11px 14px", borderRadius: 11, background: C.surface, border: `1px solid ${C.line}`, fontWeight: 800, fontSize: 17, letterSpacing: ".06em" }}>{b.ref}</div>
            <button className="softbtn" onClick={copy} style={{ padding: "0 16px", borderRadius: 11, background: C.violet, color: "#0B0D08", fontWeight: 700, fontSize: 13.5, display: "flex", alignItems: "center", gap: 6 }}>
              {copied ? <><Check size={15} /> Copied</> : <><Share2 size={15} /> Copy</>}
            </button>
          </div>
        </div>

        <button className="softbtn" onClick={onClose} style={{ width: "100%", marginTop: 18, padding: 14, borderRadius: 14, background: C.grad, color: "#0B0D08", fontWeight: 700, fontSize: 15.5 }}>Done</button>
      </div>
    </div>
  );
}

/* ============================== OPERATOR DASHBOARD ============================== */
function OperatorModal({ bookings: rawBookings, onClose }) {
  const todayKey = keyOf(TODAY.getFullYear(), TODAY.getMonth(), TODAY.getDate());
  const [cancelledIds, setCancelledIds] = useState(() => new Set());
  const bookings = useMemo(() => rawBookings.filter((b) => !cancelledIds.has(b.id)), [rawBookings, cancelledIds]);
  const cancelBooking = (id) => setCancelledIds((set) => { const n = new Set(set); n.add(id); return n; });
  const [pin, setPin] = useState("");
  const [authed, setAuthed] = useState(false);
  const [err, setErr] = useState(false);
  const [mc, setMc] = useState({ y: TODAY.getFullYear(), m: TODAY.getMonth() });
  const [selDay, setSelDay] = useState(null);
  const [tab, setTab] = useState("schedule");
  const [incomeView, setIncomeView] = useState("week");
  const [routeKey, setRouteKey] = useState(todayKey);

  function tryPin() {
    if (pin === OPERATOR_PIN) { setAuthed(true); setErr(false); }
    else { setErr(true); setPin(""); }
  }

  const sorted = [...bookings].sort((a, b) => (a.dateKey < b.dateKey ? -1 : a.dateKey > b.dateKey ? 1 : a.start - b.start));
  const revenue = bookings.reduce((a, b) => a + b.total, 0);
  const scooters = bookings.reduce((a, b) => a + b.qty, 0);
  const todays = sorted.filter((b) => b.dateKey === todayKey);
  const countByDay = bookings.reduce((acc, b) => { acc[b.dateKey] = (acc[b.dateKey] || 0) + 1; return acc; }, {});
  const calFirst = new Date(mc.y, mc.m, 1).getDay();
  const calDays = new Date(mc.y, mc.m + 1, 0).getDate();
  const cal = []; for (let i = 0; i < calFirst; i++) cal.push(null); for (let d = 1; d <= calDays; d++) cal.push(d);
  const moveMonth = (dir) => { let m = mc.m + dir, y = mc.y; if (m < 0) { m = 11; y--; } if (m > 11) { m = 0; y++; } setMc({ y, m }); };
  const dayBookings = (k) => sorted.filter((b) => b.dateKey === k);
  const dayLabel = (k) => { const f = bookings.find((b) => b.dateKey === k); return f ? f.dateLabel : k; };

  // income
  const parseKey = (k) => { const [y, m, d] = k.split("-").map(Number); return new Date(y, m - 1, d); };
  const sameDay = (a, b) => a.getFullYear() === b.getFullYear() && a.getMonth() === b.getMonth() && a.getDate() === b.getDate();
  const incomeOn = (dt) => bookings.filter((b) => sameDay(parseKey(b.dateKey), dt)).reduce((a, b) => a + b.total, 0);
  const weekStart = new Date(TODAY); weekStart.setDate(TODAY.getDate() - TODAY.getDay());
  const weekData = Array.from({ length: 7 }, (_, i) => { const dt = new Date(weekStart); dt.setDate(weekStart.getDate() + i); return { dt, val: incomeOn(dt) }; });
  const todayIncome = incomeOn(TODAY);
  const weekIncome = weekData.reduce((a, x) => a + x.val, 0);
  const monthIncome = bookings.filter((b) => { const d = parseKey(b.dateKey); return d.getMonth() === TODAY.getMonth() && d.getFullYear() === TODAY.getFullYear(); }).reduce((a, b) => a + b.total, 0);
  const avgValue = bookings.length ? Math.round(revenue / bookings.length) : 0;

  // focused day = the day being viewed on the calendar (selected, else today)
  const focusKey = selDay || todayKey;
  const focusList = dayBookings(focusKey);
  const focusScooters = focusList.reduce((a, b) => a + (b.qty || 0), 0);
  const focusIncome = focusList.reduce((a, b) => a + b.total, 0);
  const focusLabel = selDay ? "Selected day" : "Today";

  // daily route / itinerary
  const fmtDay = (k) => parseKey(k).toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric" });
  const stepRoute = (delta) => { const d = parseKey(routeKey); d.setDate(d.getDate() + delta); setRouteKey(keyOf(d.getFullYear(), d.getMonth(), d.getDate())); };
  const routeList = dayBookings(routeKey).slice().sort((a, b) => a.start - b.start);
  const routeScooters = routeList.reduce((a, b) => a + b.qty, 0);
  const upcomingRouteDays = [...new Set(bookings.map((b) => b.dateKey))].filter((k) => k >= todayKey).sort().slice(0, 8);
  const mapsHref = (() => {
    if (!routeList.length) return null;
    const enc = encodeURIComponent;
    const a = routeList.map((b) => b.address);
    if (a.length === 1) return `https://www.google.com/maps/dir/?api=1&destination=${enc(a[0])}`;
    const wp = a.slice(1, -1).map(enc).join("|");
    return `https://www.google.com/maps/dir/?api=1&origin=${enc(a[0])}&destination=${enc(a[a.length - 1])}${wp ? `&waypoints=${wp}` : ""}`;
  })();

  return (
    <div onClick={onClose} className="scrim" style={{ position: "fixed", inset: 0, zIndex: 82, background: "rgba(0,0,0,.55)", display: "grid", placeItems: "center", padding: 16 }}>
      <div onClick={(e) => e.stopPropagation()} style={{ width: authed ? "min(680px,100%)" : "min(360px,100%)", maxHeight: "92vh", overflow: "auto", background: C.surface, borderRadius: 24, boxShadow: "0 40px 90px -30px rgba(0,0,0,.7)", animation: "pop .26s cubic-bezier(.2,.8,.2,1)" }}>
        {!authed ? (
          <div style={{ padding: 30, textAlign: "center" }}>
            <div style={{ width: 56, height: 56, borderRadius: 16, background: C.grad, display: "grid", placeItems: "center", margin: "0 auto 14px" }}><Lock size={26} color="#0B0D08" /></div>
            <h2 className="disp" style={{ fontSize: 22, fontWeight: 800 }}>Operator login</h2>
            <p style={{ color: C.mute, fontSize: 13.5, marginTop: 4, marginBottom: 18 }}>Enter your 4-digit code to open the dashboard.</p>
            <input value={pin} onChange={(e) => { setPin(e.target.value.replace(/\D/g, "").slice(0, 4)); setErr(false); }}
              onKeyDown={(e) => e.key === "Enter" && tryPin()} inputMode="numeric" placeholder="••••" autoFocus
              style={{ width: 160, textAlign: "center", letterSpacing: ".5em", padding: "13px 0", borderRadius: 12, border: `1.5px solid ${err ? C.low : C.line}`, fontSize: 24, fontWeight: 800, color: C.ink, outline: "none" }} />
            {err && <p style={{ color: C.low, fontSize: 12.5, fontWeight: 600, marginTop: 8 }}>Wrong code. Try again.</p>}
            <button className="softbtn" onClick={tryPin} style={{ display: "block", width: "100%", marginTop: 16, padding: 13, borderRadius: 13, background: C.grad, color: "#0B0D08", fontWeight: 700, fontSize: 15 }}>Unlock</button>
            <p style={{ fontSize: 11, color: C.mute, marginTop: 12 }}>Demo code: 0000 · replace with real sign-in before launch.</p>
            <button className="softbtn" onClick={onClose} style={{ marginTop: 8, fontSize: 12.5, color: C.mute, fontWeight: 600 }}>Cancel</button>
          </div>
        ) : (
          <div>
            <div style={{ position: "sticky", top: 0, background: C.surface, padding: "18px 22px", borderBottom: `1px solid ${C.line}`, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <span className="disp" style={{ fontSize: 20, fontWeight: 800, display: "flex", alignItems: "center", gap: 8 }}><LayoutDashboard size={20} color={C.violet} /> Operator dashboard</span>
              <button className="softbtn" onClick={onClose} style={{ width: 34, height: 34, borderRadius: 999, background: C.paper, display: "grid", placeItems: "center" }}><X size={18} /></button>
            </div>

            <div style={{ padding: 22 }}>
              {/* tab switcher */}
              <div style={{ display: "flex", gap: 4, background: C.paper, borderRadius: 12, padding: 4, marginBottom: 18 }}>
                {[["schedule", "Schedule", CalendarDays], ["routes", "Routes", Navigation], ["income", "Income", LayoutDashboard]].map(([id, label, Icon]) => (
                  <button key={id} className="softbtn" onClick={() => setTab(id)}
                    style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 7, padding: "10px 0", borderRadius: 9, fontWeight: 700, fontSize: 14, background: tab === id ? C.surface : "transparent", color: tab === id ? C.ink : C.mute, boxShadow: tab === id ? "0 2px 8px -4px rgba(0,0,0,.3)" : "none" }}>
                    <Icon size={16} color={tab === id ? C.violet : C.mute} /> {label}
                  </button>
                ))}
              </div>

              {tab === "schedule" ? (
                <>
                  {/* highlight strip */}
                  <div style={{ display: "flex", gap: 10, marginBottom: 16 }}>
                    <MiniStat label={focusLabel} value={`${focusList.length} ${focusList.length === 1 ? "run" : "runs"}`} sub={money(focusIncome)} grad />
                    <MiniStat label="Scooters out" value={focusScooters} sub={selDay ? "this day" : "today"} />
                  </div>

                  {/* booking calendar */}
                  <div style={{ border: `1px solid ${C.line}`, borderRadius: 16, padding: 16, marginBottom: 18 }}>
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}>
                      <span className="disp" style={{ fontSize: 16, fontWeight: 700 }}>{MONTHS[mc.m]} {mc.y}</span>
                      <div style={{ display: "flex", gap: 6 }}>
                        <button className="softbtn" onClick={() => moveMonth(-1)} style={navBtn}><ChevronLeft size={17} /></button>
                        <button className="softbtn" onClick={() => moveMonth(1)} style={navBtn}><ChevronRight size={17} /></button>
                      </div>
                    </div>
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 3, marginBottom: 3 }}>
                      {["S", "M", "T", "W", "T", "F", "S"].map((d, i) => <div key={i} style={{ textAlign: "center", fontSize: 10.5, fontWeight: 700, color: C.mute }}>{d}</div>)}
                    </div>
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 3 }}>
                      {cal.map((d, i) => {
                        if (!d) return <div key={i} />;
                        const k = keyOf(mc.y, mc.m, d), count = countByDay[k] || 0, sel = k === selDay, isToday = k === todayKey;
                        return (
                          <button key={i} disabled={!count} onClick={() => setSelDay(sel ? null : k)}
                            style={{ position: "relative", aspectRatio: "1", borderRadius: 9, fontSize: 12.5, fontWeight: 600, background: sel ? C.grad : count ? `rgba(166,230,53,.08)` : "transparent", color: sel ? "#0B0D08" : count ? C.ink : "#4C5440", border: isToday && !sel ? `1.5px solid ${C.violet}` : "1.5px solid transparent", cursor: count ? "pointer" : "default" }}>
                            {d}
                            {count > 0 && !sel && <span style={{ position: "absolute", top: 2, right: 3, minWidth: 14, height: 14, borderRadius: 8, background: C.grad, color: "#0B0D08", fontSize: 9, fontWeight: 800, display: "grid", placeItems: "center", padding: "0 3px" }}>{count}</span>}
                          </button>
                        );
                      })}
                    </div>
                    <p style={{ fontSize: 11.5, color: C.mute, marginTop: 9 }}>The number on a day is how many bookings it has. Tap a day to see just those.</p>
                  </div>

                  {selDay ? (
                    <>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                        <span style={{ fontWeight: 800, fontSize: 14 }}>{dayLabel(selDay)}</span>
                        <button className="softbtn" onClick={() => setSelDay(null)} style={{ fontSize: 12.5, fontWeight: 600, color: C.violet }}>Show all</button>
                      </div>
                      <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>{dayBookings(selDay).map((b) => <OpRow key={b.id} b={b} onCancel={cancelBooking} />)}</div>
                    </>
                  ) : (
                    <>
                      <div style={{ fontWeight: 800, fontSize: 14, marginBottom: 8 }}>Today's runsheet</div>
                      {todays.length === 0 ? (
                        <div style={{ background: C.paper, borderRadius: 12, padding: 14, fontSize: 13.5, color: C.mute }}>No deliveries scheduled for today.</div>
                      ) : (
                        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>{todays.map((b) => <OpRow key={b.id} b={b} onCancel={cancelBooking} />)}</div>
                      )}
                      <div style={{ fontWeight: 800, fontSize: 14, margin: "18px 0 8px" }}>Upcoming bookings</div>
                      {sorted.length === 0 ? (
                        <div style={{ background: C.paper, borderRadius: 12, padding: 14, fontSize: 13.5, color: C.mute }}>Nothing booked yet.</div>
                      ) : (
                        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>{sorted.map((b) => <OpRow key={b.id} b={b} showDate onCancel={cancelBooking} />)}</div>
                      )}
                    </>
                  )}
                </>
              ) : tab === "income" ? (
                <>
                  {/* income cards */}
                  <div className="op-cards" style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 10, marginBottom: 14 }}>
                    <BigStat label="Today" value={money(todayIncome)} grad />
                    <BigStat label="This week" value={money(weekIncome)} />
                    <BigStat label="This month" value={money(monthIncome)} />
                  </div>

                  {/* week / month toggle */}
                  <div style={{ display: "flex", gap: 4, background: C.paper, borderRadius: 11, padding: 4, marginBottom: 16, maxWidth: 240 }}>
                    {[["week", "Weekly"], ["month", "Monthly"]].map(([id, label]) => (
                      <button key={id} className="softbtn" onClick={() => setIncomeView(id)}
                        style={{ flex: 1, padding: "8px 0", borderRadius: 8, fontWeight: 700, fontSize: 13.5, background: incomeView === id ? C.violet : "transparent", color: incomeView === id ? "#0B0D08" : C.mute }}>
                        {label}
                      </button>
                    ))}
                  </div>

                  {incomeView === "week" ? (
                    <>
                      <div style={{ border: `1px solid ${C.line}`, borderRadius: 16, padding: 16, marginBottom: 16 }}>
                        <div style={{ fontWeight: 800, fontSize: 14, marginBottom: 14 }}>This week's income</div>
                        <WeekChart data={weekData} />
                      </div>
                      <div style={{ display: "flex", gap: 10 }}>
                        <MiniStat label="All-time revenue" value={money(revenue)} sub={`${bookings.length} bookings`} />
                        <MiniStat label="Avg booking" value={money(avgValue)} sub={`${scooters} scooters booked`} />
                      </div>
                    </>
                  ) : (
                    (() => {
                      const dayInc = (d) => dayBookings(keyOf(mc.y, mc.m, d)).reduce((x, b) => x + b.total, 0);
                      const cells = cal.map((d) => (d ? dayInc(d) : 0));
                      const maxDay = Math.max(...cells, 1);
                      const monthTotal = cells.reduce((a, x) => a + x, 0);
                      const active = cells.filter((x) => x > 0).length;
                      return (
                        <div style={{ border: `1px solid ${C.line}`, borderRadius: 16, padding: 16, marginBottom: 16 }}>
                          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
                            <span className="disp" style={{ fontSize: 16, fontWeight: 700 }}>{MONTHS[mc.m]} {mc.y}</span>
                            <div style={{ display: "flex", gap: 6 }}>
                              <button className="softbtn" onClick={() => moveMonth(-1)} style={navBtn}><ChevronLeft size={17} /></button>
                              <button className="softbtn" onClick={() => moveMonth(1)} style={navBtn}><ChevronRight size={17} /></button>
                            </div>
                          </div>
                          <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 3, marginBottom: 3 }}>
                            {["S", "M", "T", "W", "T", "F", "S"].map((d, i) => <div key={i} style={{ textAlign: "center", fontSize: 10.5, fontWeight: 700, color: C.mute }}>{d}</div>)}
                          </div>
                          <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 3 }}>
                            {cal.map((d, i) => {
                              if (!d) return <div key={i} />;
                              const inc = cells[i];
                              const isToday = keyOf(mc.y, mc.m, d) === todayKey;
                              const a = inc ? (0.1 + 0.5 * (inc / maxDay)).toFixed(3) : 0;
                              return (
                                <div key={i} style={{ minHeight: 50, borderRadius: 8, padding: "4px 4px 5px", background: inc ? `rgba(166,230,53,${a})` : "transparent", border: isToday ? `1.5px solid ${C.violet}` : `1px solid ${C.line}`, display: "flex", flexDirection: "column", justifyContent: "space-between", overflow: "hidden" }}>
                                  <span style={{ fontSize: 10, fontWeight: 700, color: inc ? C.ink : C.mute }}>{d}</span>
                                  {inc > 0 && <span className="disp" style={{ fontSize: 11.5, fontWeight: 800, color: C.ink, lineHeight: 1 }}>{money(inc)}</span>}
                                </div>
                              );
                            })}
                          </div>
                          <div style={{ display: "flex", gap: 10, marginTop: 12, paddingTop: 12, borderTop: `1px solid ${C.line}` }}>
                            <div style={{ flex: 1 }}>
                              <div style={{ fontSize: 11.5, color: C.mute, fontWeight: 600 }}>{MONTHS[mc.m]} total</div>
                              <div className="disp" style={{ fontSize: 17, fontWeight: 800, color: C.violet }}>{money(monthTotal)}</div>
                            </div>
                            <div style={{ flex: 1, textAlign: "right" }}>
                              <div style={{ fontSize: 11.5, color: C.mute, fontWeight: 600 }}>Event days</div>
                              <div className="disp" style={{ fontSize: 17, fontWeight: 800 }}>{active}</div>
                            </div>
                          </div>
                        </div>
                      );
                    })()
                  )}
                  <p style={{ fontSize: 11.5, color: C.mute, marginTop: 14 }}>Income counts each booking on its event date. Connect payments to track money actually collected.</p>
                </>
              ) : (
                <>
                  {/* route day nav */}
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
                    <button className="softbtn" onClick={() => stepRoute(-1)} style={navBtn}><ChevronLeft size={17} /></button>
                    <div style={{ textAlign: "center" }}>
                      <div className="disp" style={{ fontSize: 15, fontWeight: 800 }}>{fmtDay(routeKey)}</div>
                      <div style={{ fontSize: 11.5, color: C.mute, fontWeight: 600 }}>{routeList.length} {routeList.length === 1 ? "stop" : "stops"} · {routeScooters} scooters out</div>
                    </div>
                    <button className="softbtn" onClick={() => stepRoute(1)} style={navBtn}><ChevronRight size={17} /></button>
                  </div>

                  {upcomingRouteDays.length > 0 && (
                    <div style={{ display: "flex", gap: 6, overflowX: "auto", paddingBottom: 8, marginBottom: 8 }}>
                      {upcomingRouteDays.map((k) => {
                        const on = k === routeKey, d = parseKey(k);
                        return <button key={k} className="softbtn" onClick={() => setRouteKey(k)} style={{ flex: "0 0 auto", padding: "6px 11px", borderRadius: 999, fontSize: 12, fontWeight: 700, background: on ? C.violet : C.surface, color: on ? "#0B0D08" : C.ink, border: `1px solid ${on ? "transparent" : C.line}` }}>{MONTHS[d.getMonth()].slice(0, 3)} {d.getDate()}</button>;
                      })}
                    </div>
                  )}

                  {routeList.length === 0 ? (
                    <div style={{ background: C.paper, borderRadius: 14, padding: 22, textAlign: "center", color: C.mute, fontSize: 13.5 }}>No deliveries this day. Use the arrows, or pick an upcoming day above.</div>
                  ) : (
                    <>
                      <a href={mapsHref} target="_blank" rel="noopener noreferrer" className="softbtn" style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8, width: "100%", padding: 13, borderRadius: 13, background: C.grad, color: "#0B0D08", fontWeight: 800, fontSize: 14.5, marginBottom: 16, textDecoration: "none" }}>
                        <Navigation size={17} color="#0B0D08" /> Open route in Google Maps
                      </a>
                      <div>
                        {routeList.map((b, i) => {
                          const parts = b.window.split(" – ");
                          return (
                            <div key={b.id}>
                              <div style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
                                <div style={{ flex: "0 0 auto", width: 30, height: 30, borderRadius: 999, background: C.grad, color: "#0B0D08", display: "grid", placeItems: "center", fontWeight: 800, fontSize: 14 }}>{i + 1}</div>
                                <div style={{ flex: 1, minWidth: 0, border: `1px solid ${C.line}`, borderRadius: 14, padding: "11px 13px" }}>
                                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 8 }}>
                                    <span style={{ fontWeight: 800, fontSize: 14.5 }}>{b.name}</span>
                                    <span style={{ flexShrink: 0, fontSize: 11.5, fontWeight: 700, color: C.violet, background: "rgba(166,230,53,.12)", padding: "3px 8px", borderRadius: 999 }}>{b.qty} scooters</span>
                                  </div>
                                  <div style={{ display: "flex", alignItems: "flex-start", gap: 6, marginTop: 6, fontSize: 12.5, color: C.mute }}>
                                    <MapPin size={14} style={{ flexShrink: 0, marginTop: 1 }} /> <span>{b.address}</span>
                                  </div>
                                  <div style={{ display: "flex", flexWrap: "wrap", gap: "4px 14px", marginTop: 6, fontSize: 12, color: C.mute, fontWeight: 600 }}>
                                    <span style={{ display: "flex", alignItems: "center", gap: 5 }}><Truck size={13} color={C.violet} /> Drop-off {parts[0]}</span>
                                    <span style={{ display: "flex", alignItems: "center", gap: 5 }}><Clock size={13} /> Pickup ~{parts[1]}</span>
                                  </div>
                                  {b.notes && <div style={{ marginTop: 7, fontSize: 12, color: C.ink, background: C.paper, borderRadius: 9, padding: "7px 9px" }}>{b.notes}</div>}
                                  <a href={`tel:${b.phone.replace(/[^0-9]/g, "")}`} className="softbtn" style={{ display: "inline-flex", alignItems: "center", gap: 5, marginTop: 8, fontSize: 12, fontWeight: 700, color: C.violet, textDecoration: "none" }}><Phone size={12} /> {b.phone}</a>
                                </div>
                              </div>
                              {i < routeList.length - 1 && (
                                <div style={{ display: "flex", alignItems: "center", gap: 8, margin: "4px 0 4px 15px", color: C.mute }}>
                                  <ArrowDown size={15} color={C.violet} />
                                  <span style={{ fontSize: 11.5, fontWeight: 600 }}>drive to next stop</span>
                                </div>
                              )}
                            </div>
                          );
                        })}
                      </div>
                      <p style={{ fontSize: 11.5, color: C.mute, marginTop: 14 }}>Stops are ordered by drop-off time. The Maps button opens turn-by-turn directions through every stop in order.</p>
                    </>
                  )}
                </>
              )}

              <button className="softbtn" onClick={() => { setAuthed(false); setPin(""); setSelDay(null); }} style={{ marginTop: 22, display: "flex", alignItems: "center", gap: 7, fontSize: 13, fontWeight: 600, color: C.mute }}>
                <LogOut size={15} /> Lock dashboard
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
function Stat({ label, value }) {
  return (
    <div style={{ background: C.paper, borderRadius: 14, padding: "13px 14px" }}>
      <div className="disp" style={{ fontSize: 23, fontWeight: 800 }}>{value}</div>
      <div style={{ fontSize: 12, color: C.mute, fontWeight: 600, marginTop: 1 }}>{label}</div>
    </div>
  );
}
function BigStat({ label, value, grad }) {
  return (
    <div style={{ borderRadius: 16, padding: "15px 14px", background: grad ? C.grad : C.paper, color: grad ? "#0B0D08" : C.ink }}>
      <div style={{ fontSize: 11.5, fontWeight: 700, opacity: grad ? 0.9 : 0.6, marginBottom: 4 }}>{label}</div>
      <div className="disp" style={{ fontSize: "clamp(17px,5vw,22px)", fontWeight: 800, letterSpacing: "-.02em" }}>{value}</div>
    </div>
  );
}
function MiniStat({ label, value, sub, grad }) {
  return (
    <div style={{ flex: 1, borderRadius: 14, padding: "13px 14px", background: grad ? C.grad : C.paper, color: grad ? "#0B0D08" : C.ink }}>
      <div style={{ fontSize: 11, fontWeight: 700, opacity: grad ? 0.9 : 0.6 }}>{label}</div>
      <div className="disp" style={{ fontSize: 19, fontWeight: 800, marginTop: 2 }}>{value}</div>
      {sub && <div style={{ fontSize: 11.5, fontWeight: 600, opacity: grad ? 0.85 : 0.55, marginTop: 1 }}>{sub}</div>}
    </div>
  );
}
function WeekChart({ data }) {
  const max = Math.max(...data.map((x) => x.val), 1);
  const total = data.reduce((a, x) => a + x.val, 0);
  const active = data.filter((x) => x.val > 0).length;
  const avg = active ? Math.round(total / active) : 0;
  const dows = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
  const isToday = (dt) => dt.getFullYear() === TODAY.getFullYear() && dt.getMonth() === TODAY.getMonth() && dt.getDate() === TODAY.getDate();
  const H = 150; // plot height in px
  return (
    <div>
      <div style={{ position: "relative", height: H, marginBottom: 6 }}>
        {/* gridlines */}
        {[0, 0.25, 0.5, 0.75, 1].map((g, i) => (
          <div key={i} style={{ position: "absolute", left: 0, right: 0, bottom: g * H, height: 1, background: C.line, opacity: g === 0 ? 1 : 0.5 }} />
        ))}
        {/* bars */}
        <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "flex-end", justifyContent: "space-between", gap: 9 }}>
          {data.map((x, i) => {
            const h = x.val ? Math.max(Math.round((x.val / max) * H), 4) : 0;
            const today = isToday(x.dt);
            return (
              <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "flex-end", height: "100%" }}>
                {x.val > 0 && <span className="disp" style={{ fontSize: 10.5, fontWeight: 800, color: today ? C.violet : C.ink, marginBottom: 3 }}>${x.val}</span>}
                <div style={{ width: "100%", maxWidth: 34, height: h, borderRadius: "6px 6px 2px 2px", background: today ? C.grad : x.val ? `linear-gradient(180deg, rgba(166,230,53,.8), rgba(166,230,53,.33))` : "transparent", boxShadow: today ? "0 0 16px -2px rgba(166,230,53,.5)" : "none" }} />
              </div>
            );
          })}
        </div>
      </div>
      {/* axis */}
      <div style={{ display: "flex", justifyContent: "space-between", gap: 9 }}>
        {data.map((x, i) => {
          const today = isToday(x.dt);
          return (
            <div key={i} style={{ flex: 1, textAlign: "center" }}>
              <div style={{ fontSize: 10.5, fontWeight: 700, color: today ? C.violet : C.mute }}>{dows[x.dt.getDay()][0]}</div>
              <div style={{ fontSize: 9.5, fontWeight: 600, color: today ? C.violet : C.mute, opacity: 0.7 }}>{x.dt.getDate()}</div>
            </div>
          );
        })}
      </div>
      <div style={{ display: "flex", gap: 10, marginTop: 12, paddingTop: 12, borderTop: `1px solid ${C.line}` }}>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 11.5, color: C.mute, fontWeight: 600, marginBottom: 1 }}>Week total</div>
          <div className="disp" style={{ fontSize: 17, fontWeight: 800, color: C.violet }}>{money(total)}</div>
        </div>
        <div style={{ flex: 1, textAlign: "right" }}>
          <div style={{ fontSize: 11.5, color: C.mute, fontWeight: 600, marginBottom: 1 }}>Weekly avg / event day</div>
          <div className="disp" style={{ fontSize: 17, fontWeight: 800, color: C.amber }}>{money(avg)}</div>
        </div>
      </div>
    </div>
  );
}
function OpRow({ b, showDate, onCancel }) {
  const [confirming, setConfirming] = useState(false);
  return (
    <div style={{ border: `1px solid ${C.line}`, borderRadius: 13, padding: "12px 13px" }}>
      <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 10 }}>
        <div style={{ minWidth: 0 }}>
          <div style={{ fontWeight: 700, fontSize: 14 }}>{b.qty} scooter{b.qty > 1 ? "s" : ""} · {b.window}</div>
          {showDate && <div style={{ fontSize: 12.5, color: C.mute, marginTop: 1 }}>{b.dateLabel}</div>}
        </div>
        <div style={{ textAlign: "right", flexShrink: 0 }}>
          <div className="disp" style={{ fontWeight: 800, fontSize: 14 }}>{money(b.total)}</div>
          <div style={{ display: "flex", gap: 6, justifyContent: "flex-end", marginTop: 2 }}>
            <span title="Waiver" style={{ fontSize: 10.5, fontWeight: 700, color: b.waiverSignedAt ? C.good : C.low, display: "flex", alignItems: "center", gap: 3 }}><PenLine size={11} /> {b.waiverSignedAt ? "Signed" : "Unsigned"}</span>
            {b.protect && <span title="Damage protection" style={{ fontSize: 10.5, fontWeight: 700, color: C.violet, display: "flex", alignItems: "center", gap: 3 }}><ShieldCheck size={11} /> Protected</span>}
          </div>
        </div>
      </div>
      <div style={{ borderTop: `1px solid ${C.line}`, marginTop: 9, paddingTop: 9, display: "flex", flexDirection: "column", gap: 5 }}>
        <Info icon={Users} text={b.name || "—"} />
        <Info icon={Phone} text={`${b.phone || "no phone"}  ·  ${b.email || ""}`} />
        <Info icon={MapPin} text={b.address || "no address"} accent />
        {b.notes && <Info icon={StickyNote} text={b.notes} />}
      </div>
      {onCancel && (confirming ? (
        <div style={{ marginTop: 10, display: "flex", gap: 8 }}>
          <button className="softbtn" onClick={() => setConfirming(false)} style={{ flex: 1, padding: "8px 0", borderRadius: 9, background: C.paper, border: `1px solid ${C.line}`, color: C.ink, fontWeight: 700, fontSize: 12.5 }}>Keep</button>
          <button className="softbtn" onClick={() => { onCancel(b.id); setConfirming(false); }} style={{ flex: 1, padding: "8px 0", borderRadius: 9, background: C.pink, color: "#0B0D08", fontWeight: 800, fontSize: 12.5 }}>Confirm cancel</button>
        </div>
      ) : (
        <button className="softbtn" onClick={() => setConfirming(true)} style={{ marginTop: 10, display: "flex", alignItems: "center", gap: 5, fontSize: 12, fontWeight: 700, color: C.mute }}><X size={12} /> Cancel this booking</button>
      ))}
    </div>
  );
}
function Info({ icon: Icon, text, accent }) {
  return (
    <div style={{ display: "flex", gap: 7, alignItems: "flex-start", fontSize: 12.5, color: accent ? C.ink : C.mute }}>
      <Icon size={13} color={accent ? C.pink : C.mute} style={{ marginTop: 1, flexShrink: 0 }} />
      <span style={{ fontWeight: accent ? 600 : 500, lineHeight: 1.35 }}>{text}</span>
    </div>
  );
}
